#include "biblia.h"

void Biblia::Carregar3Joao(Biblia* b) {
    b->dados[JOAO3].nome = wxT("3 João");

    b->dados[JOAO3].capitulos[1].versos[1] = wxT("O ancião ao amado Gaio, a quem eu amo em verdade.");
    b->dados[JOAO3].capitulos[1].versos[2] = wxT("Amado, desejo que te vá bem em todas as coisas, e que tenhas saúde, assim como bem vai à tua alma.");
    b->dados[JOAO3].capitulos[1].versos[3] = wxT("Porque muito me alegrei quando os irmãos vieram e testificaram da tua verdade, como tu andas na verdade.");
    b->dados[JOAO3].capitulos[1].versos[4] = wxT("Não tenho maior gozo do que este: o de ouvir que os meus filhos andam na verdade.");
    b->dados[JOAO3].capitulos[1].versos[5] = wxT("Amado, procedes fielmente em tudo o que fazes para com os irmãos, especialmente para com os estranhos,");
    b->dados[JOAO3].capitulos[1].versos[6] = wxT("os quais diante da igreja testificaram do teu amor; aos quais, se os encaminhares na sua viagem de um modo digno de Deus, bem farás;");
    b->dados[JOAO3].capitulos[1].versos[7] = wxT("porque por amor do Nome saíram, sem nada aceitar dos gentios.");
    b->dados[JOAO3].capitulos[1].versos[8] = wxT("Portanto aos tais devemos acolher, para que sejamos cooperadores da verdade.");
    b->dados[JOAO3].capitulos[1].versos[9] = wxT("Escrevi alguma coisa à igreja; mas Diótrefes, que gosta de ter entre eles a primazia, não nos recebe.");
    b->dados[JOAO3].capitulos[1].versos[10] = wxT("Pelo que, se eu aí for, trarei à memória as obras que ele faz, proferindo contra nós palavras maliciosas; e, não contente com isto, ele não somente deixa de receber os irmãos, mas aos que os querem receber ele proíbe de o fazerem e ainda os exclui da igreja.");
    b->dados[JOAO3].capitulos[1].versos[11] = wxT("Amado, não imites o mal, mas o bem. Quem faz o bem é de Deus; mas quem faz o mal não tem visto a Deus.");
    b->dados[JOAO3].capitulos[1].versos[12] = wxT("De Demétrio, porém, todos, e até a própria verdade, dão testemunho; e nós também damos testemunho; e sabes que o nosso testemunho é verdadeiro.");
    b->dados[JOAO3].capitulos[1].versos[13] = wxT("Tinha eu muitas coisas que te escrever, mas não o quero fazer com tinta e pena.");
    b->dados[JOAO3].capitulos[1].versos[14] = wxT("Espero, porém, ver-te brevemente, e falaremos face a face.");
    b->dados[JOAO3].capitulos[1].versos[15] = wxT("Paz seja contigo. Os amigos te saúdam. Saúda os amigos nominalmente.");

}
